// bottom form
$('#reqaccessfrm').validate({
    rules:{
        'available_money' : { required : true },
        'hold_period' : { required : true },
        'name' : { required : true},
        'email' : { required : true, email: true},
        'phone' : { required : true},
    },
    messages:{
        'available_money' : { required : "Please enter how much money do you have available to invest in this fund."},
        'hold_period' : { required : "Please enter how long of a hold period are you comfortable with."},
        'name' : { required : "Please enter your full name."},
        'email' : { required : "Please enter your valid email."},
        'phone' : { required : "Please enter your valid phone number."},
    },
    highlight: function(element) {
        $(element).removeClass("error");
    }
});
// bottom form
$('#reqaccessfrm').submit(function(e){
    e.preventDefault();
    if($('#reqaccessfrm').validate().valid())
    {
        //return true;
        $('#reqaccessbtn').html('Loading...');
        $('#reqaccessbtn').attr('disabled',true);
        $.ajax({
            url: $('#sitepath').val()+'acquisitionfunding/requestaccess',
            data: $('#reqaccessfrm').serialize(),
            dataType: 'json', 
            type: 'post',
            success: function(data) {
                //console.log("bottom form",data);
                if(data.status)
                {
                    $('.successmessagereqaccess').show();
                    $('#successmessagereqaccess').html('We have received your information. ONe of our team member will contact you soon.');
                    $('#errormessagereqaccess').html('');
                    $('.errormessagereqaccess').hide();
                }else{
                    $('.successmessagereqaccess').hide();
                    $('#successmessagereqaccess').html('');
                    $('.errormessagereqaccess').show();
                    //console.log(data.message);
                    $('#errormessagereqaccess').html('');
                    $.each(data.message,(item,val)=>{
                        //console.log(item);
                        $('#errormessagereqaccess').append(`<li>${val}</li>`);
                    });
                }
                //console.log(data);
                $('#reqaccessbtn').html('Submit');
                $('#reqaccessbtn').attr('disabled',false);
                $('.csrftoken').val(data.token);
                

            }             
        });
    }
    
    return false;
});
